        `;
        homeScreen.appendChild(page);
    });

    updateEditorDots();

ops.find_block:
function addToHome(pkg) {
    // If dock has room, put it there. Otherwise, put it in the home grid.
    if (dockPkgs.length < 4 && !dockPkgs.includes(pkg)) {
        dockPkgs.push(pkg);
        localStorage.setItem('cortex_dock', JSON.stringify(dockPkgs));
    } else if (!homeShortcuts.includes(pkg) && !dockPkgs.includes(pkg)) {
        homeShortcuts.push(pkg);
        localStorage.setItem('cortex_home_grid', JSON.stringify(homeShortcuts));
    }
    renderAll(allApps);
    closeMenu();
}

