function updateDots() {
    closeMenu();
    const pager = document.getElementById('pager');
    const dots = document.querySelectorAll('.dot');
    const idx = Math.round(pager.scrollLeft / window.innerWidth);
    dots.forEach((d, i) => d.classList.toggle('active', i === idx));
}

ops.replace_with:
function updateDots() {
    closeMenu();
    const pager = document.getElementById('pager');
    const dots = document.querySelectorAll('#dots .dot');
    const idx = Math.round(pager.scrollLeft / window.innerWidth);
    dots.forEach((d, i) => d.classList.toggle('active', i === idx));
}

function updateEditorDots() {
    const dotsBox = document.getElementById('editor-dots');
    if(!dotsBox) return;
    dotsBox.innerHTML = '';
    const idx = Math.round(document.getElementById('home-screen').scrollLeft / window.innerWidth);
    homePages.forEach((_, i) => {
        const d = document.createElement('div');
        d.className = 'dot' + (i === idx ? ' active' : '');
        d.style.cssText = "width:8px; height:8px; background:" + (i === idx ? '#fff' : '#444') + "; border-radius:50%;";
        dotsBox.appendChild(d);
    });
}

// EDITOR LOGIC
function isEditorActive() { return document.body.classList.contains('editor-active'); }

function handleHomeTouchStart(e) {
    if (isEditorActive()) return;
    // Only trigger if we touch the background, not an app
    if (e.target.closest('.app-item')) return;

    homePressTimer = setTimeout(() => {
        enterEditorMode();
    }, 600);
}

function handleHomeTouchEnd() {
    clearTimeout(homePressTimer);
}

function enterEditorMode() {
    document.body.classList.add('editor-active');
    updateEditorDots();
}

function addHomePage() {
    homePages.push([]);
    localStorage.setItem('cortex_home_pages', JSON.stringify(homePages));
    renderAll(allApps);
}

function removeHomePage(idx) {
    if (homePages.length <= 1) return;
    homePages.splice(idx, 1);
    localStorage.setItem('cortex_home_pages', JSON.stringify(homePages));
    renderAll(allApps);
}

document.getElementById('home-screen').onscroll = () => {
    if(isEditorActive()) updateEditorDots();
};

