    // 1. Close context menu if open
    const menu = document.getElementById('context-menu');
    if (menu && menu.style.display === 'flex') {
        closeMenu();
        return true;
    }
    // 2. Close Editor if active
    if (document.body.classList.contains('editor-active')) {
        document.body.classList.remove('editor-active');
        return true;
    }
    // 3. Close app drawer if open
    if (document.body.classList.contains('drawer-active')) {
        showHomeScreen();
        return true;
    }
    return false;
};

